class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}
        for i in range(len(s)):
            count_s[s[i]] = 1 + count_s.get(s[i], 0)
            count_t[t[i]] = 1 + count_t.get(t[i], 0)
        diff = 0
        for c in count_s:
            diff += abs(count_s[c] - count_t.get(c, 0))
        return diff // 2
```
